kernel_src="""

#include "kernel_operator.h"

class KernelCumprodCustom {
public:
    __aicore__ inline KernelCumprodCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t rowLength,
                                uint32_t numRows, uint32_t blockDim)
    {
        totalLen_ = totalLength;
        rowLen_ = rowLength;
        numRows_ = numRows;
        blockDim_ = blockDim;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        // Single buffer for in-place computation: sufficient UB for one row
        pipe_.InitBuffer(tmpBuf_, 1, rowLen_ * sizeof(float));  // FIX: added '1' as num buffer argument
    }

    __aicore__ inline void Process()
    {
        if (rowLen_ == 0 || numRows_ == 0) return;

        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t rowsPerBlock = (numRows_ + blockDim_ - 1) / blockDim_;
        uint32_t startRow = blockIdx * rowsPerBlock;
        if (startRow >= numRows_) return;
        uint32_t endRow = startRow + rowsPerBlock;
        if (endRow > numRows_) endRow = numRows_;

        for (uint32_t r = startRow; r < endRow; ++r) {
            uint32_t offset = r * rowLen_;

            // Load row into local buffer
            AscendC::LocalTensor<float> buf = tmpBuf_.AllocTensor<float>();
            AscendC::DataCopy(buf, xGm_[offset], rowLen_);

            // In-place cumulative product
            float prod = 1.0f;
            for (uint32_t i = 0; i < rowLen_; ++i) {
                prod *= buf(i);
                buf(i) = prod;
            }

            // Store result
            AscendC::DataCopy(yGm_[offset], buf, rowLen_);
            tmpBuf_.FreeTensor(buf);
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpBuf_;  // single buffer, reused per row

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t rowLen_ {0};
    uint32_t numRows_ {0};
    uint32_t blockDim_ {1};
};

extern "C" __global__ __aicore__ void cumprod_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCumprodCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.rowLength, tiling_data.numRows, tiling_data.blockDim);
    op.Process();
}
